impl Solution { pub fn min_time(n: i32, mut black_e: Vec<Vec<i32>>, k: i32) -> i32 { let mut black_p: Vec<usize> = (0..n as usize).collect(); black_e.sort_unstable_by_key(|black_v| std::cmp::Reverse(black_v[2])); let mut black_c = n; for black_v in black_e { let (mut black_r1, mut black_r2) = (black_v[0] as usize, black_v[1] as usize); while black_r1 != black_p[black_r1] { black_p[black_r1] = black_p[black_p[black_r1]]; black_r1 = black_p[black_r1]; } while black_r2 != black_p[black_r2] { black_p[black_r2] = black_p[black_p[black_r2]]; black_r2 = black_p[black_r2]; } if black_r1 != black_r2 { black_p[black_r1] = black_r2; black_c -= 1; if black_c < k { return black_v[2]; } } } 0 } }